import{_ as e,o as a,c as p,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"“斗牛犬”重型左轮手枪","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/“斗牛犬”重型左轮手枪.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/“斗牛犬”重型左轮手枪.md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/“斗牛犬”重型左轮手枪.md"};function _(o,b,d,l,i,c){return a(),p("div",null,[...b[0]||(b[0]=[r("h1",{id:"斗牛犬-重型左轮手枪",tabindex:"-1"},[t("“斗牛犬”重型左轮手枪 "),r("a",{class:"header-anchor",href:"#斗牛犬-重型左轮手枪","aria-label":'Permalink to "“斗牛犬”重型左轮手枪"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调013")])])],-1),n('<h1 id="斗牛犬-重型左轮手枪-1" tabindex="-1">“斗牛犬”重型左轮手枪 <a class="header-anchor" href="#斗牛犬-重型左轮手枪-1" aria-label="Permalink to &quot;“斗牛犬”重型左轮手枪&quot;">​</a></h1><p>“斗牛犬”重型左轮手枪</p><p>“斗牛犬”重型左轮手枪<br> D+500<br> 这是一把体积3，武器伤害7L的重型左轮手枪。它的转轮能容纳6发子弹，速射等级为无。</p><p>每场影片结束时，按序依次选择一项改装项目，同一行只能选择一种改装，选择后不能更换。</p><p>1<br> 快速退弹器（换弹速度）<br> 长期经验、刻苦训练，外加那么亿丢丢的私下“改动”使得武器的换弹更加迅速。<br> 你的换弹动作从移动动作下降至迅捷动作。</p><p>完美配重（精准度）<br> 提升精准度。<br> 在使用“斗牛犬”重型左轮时，你额外获得1点瞄准上限，并视为已经瞄准了1轮。</p><p>2<br> 大口径弹药（伤害）<br> 研发部加班造成的身体与精神上的伤害，换取了武器的整体伤害提升。<br> 重型左轮手枪的武器伤害提升3L</p><p>浮置枪管（后坐力）<br> 完美，精致的优化。在摇了几个人后，我们设法让这把枪的稳定性显著提高了。<br> 经过稳定性改装后，你可以使用重型左轮进行连射。</p><p>3<br> 超强贯穿弹（穿透）<br> 异形弹头被设计成能以最小的动能损失穿透目标的造型，换句话说：一发直接射穿几个敌人！<br> 在选择这项改造时，它会额外获得【贯穿】效果。</p><p>空尖弹（弱点伤害加成）<br> 哪里发光点哪里！我们加强了武器对生物肉质部位的伤害。不用客气。<br> 现在，使用重型左轮攻击特殊部位时，将忽略至多3点特殊部位减值。</p><p>4<br> 高速子弹（伤害）<br> 研发部加班造成的身体与精神上的伤害，换取了武器的整体伤害提升。<br> 在选择这项改造时，它会额外提升3点高速。</p><p>5<br> 死亡之眼（精准度）<br> 移动时不产生精准度削减。<br> 现在，你可以在移动时进行瞄准，正常消耗动作，若如此做，则视为额外瞄准了一次，你的瞄准上限再提升1。</p><p>神经毒素涂层（神经毒素）<br> 有几率使你的目标中毒。受影响的生物移动更慢且受到持续伤害。<br> 使用重型左轮时，有一半概率使被你命中且成功造成伤害的目标承受1点不可豁免的毒素点数。</p><p>改造模组<br> 在重型左轮至少具有2种改装后，便可以解锁模组栏位，并解锁模组的购买权，这把枪只能同时享受一种模组带来的效果。在具有模组后，重型左轮的武器伤害将再提升6点。</p><p>连锁打击<br> C+1000<br> 无瑕超频模组<br> 命中弱点的子弹将有很高几率弹射到附近的敌人身上。<br> +命中弱点的子弹将弹射到附近的敌人身上<br> 在命中首个敌人，且攻击的是其特殊部位后，击中其的子弹将弹射到离其最近且处于你的射程范围内的一个目标身上，正常攻击其防御，并在结算伤害后重复此过程，直至射程范围内所有敌人都被攻击一次后结束这个效果。</p><p>六连射手<br> C+1000<br> 均衡超频模组<br> 改良后的弹壳设计在提升了弹药携带量的同时，使你能往转轮内硬塞进两发额外的子弹，但对子弹的小修小改影响了武器的精度和换弹速度。<br> +射速更快的六发转轮<br> -更长的换弹时间<br> 效果：现在，你的射击会视为再对被命中的目标多次攻击了六次，这会带来相应的多次攻击减值，你的射击检定再获得【9加骰】，现在，使用重型左轮进行的任何射击都会视为进行了一次消耗了所有子弹的连射，重型左轮无法获得无限子弹，或无法享受此模组带来的加成，重型左轮将无法再通过非本物品改装以外的效果下降换弹动作。</p><p>易燃子弹<br> C+1000<br> 均衡超频模组<br> 火上浇油！这些子弹对着火的目标特别有效，代价是对未着火的目标造成的直接伤害降低。<br> +对点燃目标造成额外燃烧伤害<br> -显著减少直接伤害<br> 效果：正常攻击某目标防御，在命中该目标时，若其带有燃烧点数，则对其造成本次攻击出目一半的燃烧点数，使用强韧豁免进行对抗，然后再对其造成这次攻击出目四分之一的伤害。</p><p>自制火药<br> C+1000<br> 均衡超频模组<br> 平均伤害提升，但单发伤害存在浮动。<br> +最高造成200％的伤害<br> -最低造成50％的伤害<br> 效果：每次使用重型左轮进行攻击前，先投一次D200，若出目低于50，则提升至50。这次攻击的武器伤害为（D200出目）％*重型左轮武器伤害。</p><p>巨象弹药<br> 不稳定超频模组<br> C+1000<br> 大量改动成功把左轮手枪魔改成了小型手持机炮！每发的伤害和后坐力都直冲天花板，但你的裤兜里也塞不下和之前一样多的弹药了。另外这把枪现在一次也只能装入3发子弹，装填的时间也更长，但至少基础精准度有一定提升。<br> +大幅提升伤害和精准度<br> -大幅增加后坐力<br> -装填时间更长的三发转轮<br> 效果：使用重型左轮进行攻击时，额外再提升伤害出目四分之一的伤害，但重型左轮失去所有连射等级，也不能提升连射等级；每次射击过的下一轮无法进行瞄准，重型左轮可以一发一发的装填，装填每一发弹药需要一个迅捷动作，无法以任何方式下降重型左轮的装填动作。<br> 这把手枪的弹药数量不会被其他特性所影响（例如无限弹药）。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',21)])])}const m=e(s,[["render",_]]);export{f as __pageData,m as default};
